// Fires every minute. Emits one item only when the saved schedule
// matches the current local time in GENERIC_TIMEZONE, and we have
// not already fired today.
//
// Schedule shape (in $getWorkflowStaticData('global').schedule):
//   { enabled: bool, time: 'HH:MM', lastFiredAt: 'YYYY-MM-DD' | null }
//
// Empty array = silent no-op; the rest of the workflow does not run.

const sd = $getWorkflowStaticData('global');
const sched = sd.schedule;
if (!sched || !sched.enabled || !sched.time) return [];

const tz = $env.GENERIC_TIMEZONE || 'UTC';
const now = new Date();

// Use formatToParts to avoid locale-formatting surprises (en-GB returns
// '24:xx' at midnight, some locales add ' AM/PM' or use unicode separators).
const timeParts = new Intl.DateTimeFormat('en-US', {
  timeZone: tz, hour: '2-digit', minute: '2-digit', hour12: false
}).formatToParts(now);
const dateParts = new Intl.DateTimeFormat('en-CA', {
  timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit'
}).formatToParts(now);

const getPart = (parts, type) => (parts.find(p => p.type === type) || {}).value;

// en-US 'hour: 2-digit, hour12:false' can return '24' at midnight — clamp.
let hh = getPart(timeParts, 'hour');
if (hh === '24') hh = '00';
const mm = getPart(timeParts, 'minute');
const hhmm = hh + ':' + mm;

const today = getPart(dateParts, 'year') + '-' + getPart(dateParts, 'month') + '-' + getPart(dateParts, 'day');

if (hhmm !== sched.time) return [];
if (sched.lastFiredAt === today) return [];

// Same gates as /generate: skip the scheduled run if quota cooldown is active
// or the daily cap is already reached. Don't set lastFiredAt so we don't
// burn today's slot — the gate may be the only thing in the way.
// (`now` is already declared above as `new Date()` — reuse it via .getTime().)
if (sd.cloudflareBackoffUntil && sd.cloudflareBackoffUntil > now.getTime()) return [];
const MAX_PER_DAY = 10;
const dc = sd.dailyCount;
const usedToday = (dc && dc.date === today) ? (dc.count || 0) : 0;
if (usedToday >= MAX_PER_DAY) return [];

sched.lastFiredAt = today;
return [{ json: { trigger: 'schedule', firedAt: today + ' ' + hhmm } }];

// Parse a slash command from Handle message and produce either:
//   { _action: 'generate' }                              — kick off generator
//   { _action: 'reply', replyText: '...' }               — send a single reply
//
// For show/set/disable_schedule, also reads/writes staticData.schedule
// here so the routing only needs two branches downstream.

const cmd = $json._command;
const args = ($json._args || '').trim();
const tz = $env.GENERIC_TIMEZONE || 'UTC';

const helpText = [
  'Available commands:',
  '/generate — create a new post now',
  '/schedule — show the current daily schedule',
  '/schedule HH:MM — set the daily run time (' + tz + ')',
  '/schedule off — disable the daily schedule',
  '/help — show this message',
].join('\n');

if (cmd === '/generate') {
  return [{ json: { _action: 'generate' } }];
}

if (cmd === '/help' || cmd === '/start') {
  return [{ json: { _action: 'reply', replyText: helpText } }];
}

if (cmd === '/schedule') {
  const sd = $getWorkflowStaticData('global');
  const cur = sd.schedule || {};

  if (!args) {
    const text = (cur && cur.enabled)
      ? 'Schedule: daily at ' + cur.time + ' (' + tz + ').\nLast run: ' + (cur.lastFiredAt || 'never') + '.'
      : 'Schedule is disabled. Use /schedule HH:MM to enable.';
    return [{ json: { _action: 'reply', replyText: text } }];
  }

  if (args.toLowerCase() === 'off') {
    sd.schedule = { ...cur, enabled: false };
    return [{ json: { _action: 'reply', replyText: 'Schedule disabled. Use /schedule HH:MM to re-enable.' } }];
  }

  const m = args.match(/^(\d{1,2}):(\d{2})$/);
  if (m) {
    const h = +m[1], mm = +m[2];
    if (h >= 0 && h < 24 && mm >= 0 && mm < 60) {
      const time = String(h).padStart(2, '0') + ':' + String(mm).padStart(2, '0');
      sd.schedule = {
        enabled: true,
        time,
        // Preserve lastFiredAt so we do not re-fire today if we already did.
        lastFiredAt: cur.lastFiredAt || null,
      };
      return [{ json: { _action: 'reply', replyText: 'Daily schedule set to ' + time + ' (' + tz + ').' } }];
    }
  }

  return [{ json: { _action: 'reply', replyText: 'Bad time format. Use /schedule HH:MM (24h), e.g. /schedule 09:00, or /schedule off.' } }];
}

return [{ json: { _action: 'reply', replyText: 'Unknown command ' + cmd + '.\n\n' + helpText } }];

// Reject /generate when blocked by any of:
//   - an in-flight pending preview
//   - active Cloudflare backoff (set by error handler after a quota failure)
//   - daily generation cap reached
// Field name `has_pending` is kept so the downstream IF node still routes.
// `busy_reason` is read by `Reply pending busy` to show the user why.
const sd = $getWorkflowStaticData('global');
const MAX_PER_DAY = 10;

const p = sd.pending;
const now = Date.now();
const today = new Date().toISOString().slice(0, 10);
const dc = sd.dailyCount;
const usedToday = (dc && dc.date === today) ? (dc.count || 0) : 0;

let has_pending = false;
let busy_reason = 'A preview is already pending. Approve, regenerate, or finish it first.';

if (p && p.resumeUrl) {
  has_pending = true;
} else if (sd.cloudflareBackoffUntil && sd.cloudflareBackoffUntil > now) {
  has_pending = true;
  const minutesLeft = Math.ceil((sd.cloudflareBackoffUntil - now) / 60000);
  busy_reason = '⏸ Image generator paused after a quota error. Try again in ' + minutesLeft + ' min.';
} else if (usedToday >= MAX_PER_DAY) {
  has_pending = true;
  busy_reason = 'Daily limit reached (' + usedToday + '/' + MAX_PER_DAY + '). Try again tomorrow.';
}

return [{ json: { has_pending, busy_reason } }];

// Single funnel point for the generator chain so 'Read brand voice'
// only ever has one upstream connection. Three triggers feed into here:
//   - manual trigger (When clicking Test workflow)
//   - Schedule trigger -> Check schedule (only when time matches)
//   - /generate command -> IF has pending [false]
// We just emit a marker item the rest of the chain ignores.
return [{ json: { _generator_entry: true } }];

// Format an Error Trigger payload into a human-readable Telegram message.
// On Cloudflare quota / rate-limit failures, also set a 1-hour backoff so
// the gates in `Check pending guard` and `Check schedule` reject new runs
// until the cooldown expires. This is what prevents the retry-cascade,
// not pending-state clearing.
//
// Error Trigger payload shape:
//   { execution: { id, url, error: {message, stack}, lastNodeExecuted, mode },
//     workflow:  { id, name } }

const p = $input.first().json;
const ex = p.execution || {};
const err = ex.error || {};

const node = ex.lastNodeExecuted || 'unknown node';
const message = (err.message || 'no message').toString().split('\n')[0].slice(0, 400);
const exUrl = ex.url || '';

const sd = $getWorkflowStaticData('global');

// Detect Cloudflare quota / rate-limit failures. Code 4006 = neuron quota;
// generic 429 surfaces as 'too many requests'.
const isCloudflareNode = node === 'Cloudflare image generation' || node === 'Regen image with hint';
const isQuotaError = /4006|too many requests|neurons|rate.?limit|quota/i.test(message);
let backoffApplied = false;
if (isCloudflareNode && isQuotaError) {
  sd.cloudflareBackoffUntil = Date.now() + 60 * 60 * 1000; // 1 hour
  backoffApplied = true;
}

// Clear pending so the user is not permanently stuck on a stale preview.
if (sd && sd.pending) sd.pending = null;

const lines = [
  '❌ Workflow error',
  '',
  'Node: ' + node,
  'Reason: ' + message,
];
if (backoffApplied) {
  lines.push('');
  lines.push('⏸ Image generator paused for 1 hour to avoid further quota burn.');
}
if (exUrl) lines.push('Execution: ' + exUrl);

return [{ json: { errorText: lines.join('\n') } }];
